INSERT INTO wallet_flows (
    owner_type, owner_id, biz_type, biz_id, direction, amount, status, balance_after, remark, operator_id, created_at
)
VALUES (
    #{ownerType}, #{ownerId}, #{bizType}, #{bizId}, #{direction}, #{amount}, #{status}, #{balanceAfter}, #{remark}, #{operatorId}, NOW()
)

mapper.select:
SELECT *
FROM wallet_flows
WHERE owner_type = #{ownerType} AND owner_id = #{ownerId}
ORDER BY created_at DESC, id DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM wallet_flows
WHERE owner_type = #{ownerType} AND owner_id = #{ownerId}

SELECT COALESCE(SUM(amount), 0)
FROM wallet_flows
WHERE owner_type = #{ownerType}
  AND owner_id = #{ownerId}
  AND direction = #{direction}
  AND status = 'success'
